const checkpoints = [];

function getDateStr(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

function getTimeMinutes(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  return d.getUTCHours() * 60 + d.getUTCMinutes();
}

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const slots = JSON.parse(localStorage.getItem('consultation_time_slots') || '[]');
const services = JSON.parse(localStorage.getItem('consultation_services') || '[]');

// Next Tuesday relative to baseline 2026-03-03 is 2026-03-10
const targetDate = '2026-03-10';
const earliestMinutes = 17 * 60; // 17:00

// All candidate slots that meet the task criteria (type, duration, date, time)
const candidateSlots = slots.filter(function(slot) {
  const service = services.find(function(s) { return s.id === slot.consultation_service_id; });
  if (!service) return false;
  if (service.service_type !== 'running_technique') return false;
  if (service.duration_minutes !== 60) return false;
  if (getDateStr(slot.start_datetime) !== targetDate) return false;
  const t = getTimeMinutes(slot.start_datetime);
  if (t == null || t <= earliestMinutes) return false; // strictly after 17:00
  return true;
});

let minPrice = Infinity;
candidateSlots.forEach(function(slot) {
  if (typeof slot.price === 'number' && slot.price < minPrice) {
    minPrice = slot.price;
  }
});

// Cart consultation bookings that meet the basic criteria
const qualifyingBookings = cartItems.filter(function(ci) {
  if (!ci || ci.item_type !== 'consultation' || !ci.consultation_time_slot_id) return false;
  const slot = slots.find(function(s) { return s.id === ci.consultation_time_slot_id; });
  if (!slot) return false;
  const service = services.find(function(s) { return s.id === slot.consultation_service_id; });
  if (!service) return false;
  if (service.service_type !== 'running_technique') return false;
  if (service.duration_minutes !== 60) return false;
  if (getDateStr(slot.start_datetime) !== targetDate) return false;
  const t = getTimeMinutes(slot.start_datetime);
  if (t == null || t <= earliestMinutes) return false; // after 17:00 only
  if (ci.attendees !== 1) return false;
  if (typeof slot.max_participants === 'number' && ci.attendees > slot.max_participants) return false;
  return true;
});

// CP1 (0.4): User booked at least one qualifying 60-min running technique consultation next Tuesday after 5 pm for one attendee
checkpoints.push({ passed: qualifyingBookings.length >= 1, weight: 0.4 });

// Among those, check if any uses the cheapest qualifying slot price
const cheapestQualifying = qualifyingBookings.filter(function(ci) {
  const slot = slots.find(function(s) { return s.id === ci.consultation_time_slot_id; });
  if (!slot) return false;
  if (!isFinite(minPrice)) return false;
  return typeof slot.price === 'number' && slot.price === minPrice;
});

// CP2 (0.6): At least one qualifying booking uses a slot at the minimum price among all qualifying options
checkpoints.push({ passed: cheapestQualifying.length >= 1 && isFinite(minPrice), weight: 0.6 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const tiers = JSON.parse(localStorage.getItem('program_tiers') || '[]');

// Qualifying catalog programs per task criteria
const qualifyingPrograms = programs.filter(function(p) {
  if (!p || !p.is_active) return false;
  if (p.category !== 'stress_management') return false;
  if (p.duration_weeks !== 4) return false;
  if (typeof p.base_price !== 'number' || p.base_price > 120) return false;
  if (typeof p.rating !== 'number' || p.rating < 4.5) return false;
  return true;
});

if (qualifyingPrograms.length === 0) {
  return 0;
}

const highestRating = Math.max.apply(null, qualifyingPrograms.map(function(p) { return p.rating || 0; }));
const bestPrograms = qualifyingPrograms.filter(function(p) { return (p.rating || 0) === highestRating; });

// Program enrollments in cart that match criteria and use a Standard tier
const qualifyingEnrollments = cartItems.filter(function(ci) {
  if (!ci || ci.item_type !== 'program_enrollment' || !ci.program_id) return false;
  const program = programs.find(function(p) { return p.id === ci.program_id; });
  if (!program) return false;
  const inQualifying = qualifyingPrograms.some(function(p) { return p.id === program.id; });
  if (!inQualifying) return false;
  // Tier should be Standard
  const tier = ci.program_tier_id ? tiers.find(function(t) { return t.id === ci.program_tier_id; }) : null;
  if (!tier || tier.tier_type !== 'standard') return false;
  // Ensure a start date was set (BusinessLogic enforces 0–30 day window)
  if (!ci.program_start_date) return false;
  return true;
});

// CP1 (0.4): At least one cart enrollment matches all basic criteria (stress_management, 4 weeks, price≤120, rating≥4.5, Standard tier, with a start date)
checkpoints.push({ passed: qualifyingEnrollments.length >= 1, weight: 0.4 });

// CP2 (0.6): At least one such enrollment is for the highest-rated qualifying program
const bestEnrollmentExists = qualifyingEnrollments.some(function(ci) {
  return bestPrograms.some(function(p) { return p.id === ci.program_id; });
});

checkpoints.push({ passed: bestEnrollmentExists, weight: 0.6 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

function getDateStr(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

function getTimeMinutes(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  return d.getUTCHours() * 60 + d.getUTCMinutes();
}

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const sessions = JSON.parse(localStorage.getItem('group_class_sessions') || '[]');

// Upcoming Saturday relative to baseline 2026-03-03 is 2026-03-07
const targetDate = '2026-03-07';
const windowStart = 8 * 60;  // 08:00
const windowEnd = 12 * 60;   // 12:00

const qualifyingItems = cartItems.filter(function(ci) {
  if (!ci || ci.item_type !== 'class_session' || !ci.group_class_session_id) return false;
  if (ci.attendees !== 1) return false;
  const s = sessions.find(function(x) { return x.id === ci.group_class_session_id; });
  if (!s || s.is_cancelled) return false;
  if (s.intensity !== 'moderate') return false;
  if (typeof s.duration_minutes !== 'number' || s.duration_minutes >= 45) return false;
  if (getDateStr(s.start_datetime) !== targetDate) return false;
  const t = getTimeMinutes(s.start_datetime);
  if (t == null || t < windowStart || t > windowEnd) return false;
  return true;
});

// CP1 (0.3): At least one qualifying moderate Saturday-morning class under 45 minutes with one attendee was booked
checkpoints.push({ passed: qualifyingItems.length >= 1, weight: 0.3 });

// CP2 (0.3): At least two such qualifying classes were booked
checkpoints.push({ passed: qualifyingItems.length >= 2, weight: 0.3 });

// CP3 (0.4): There exists a pair of distinct qualifying class bookings at least 30 minutes apart
let hasValidPair = false;
for (let i = 0; i < qualifyingItems.length; i++) {
  const ci1 = qualifyingItems[i];
  const s1 = sessions.find(function(x) { return x.id === ci1.group_class_session_id; });
  if (!s1) continue;
  const t1 = getTimeMinutes(s1.start_datetime);
  for (let j = i + 1; j < qualifyingItems.length; j++) {
    const ci2 = qualifyingItems[j];
    if (ci1.group_class_session_id === ci2.group_class_session_id) continue; // must be different sessions
    const s2 = sessions.find(function(x) { return x.id === ci2.group_class_session_id; });
    if (!s2) continue;
    const t2 = getTimeMinutes(s2.start_datetime);
    if (t1 == null || t2 == null) continue;
    const diff = Math.abs(t2 - t1);
    if (diff >= 30) {
      hasValidPair = true;
      break;
    }
  }
  if (hasValidPair) break;
}

checkpoints.push({ passed: hasValidPair, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('training_plans') || '[]');
const items = JSON.parse(localStorage.getItem('training_plan_items') || '[]');
const templates = JSON.parse(localStorage.getItem('workout_templates') || '[]');

if (!plans.length || !items.length || !templates.length) {
  return 0;
}

let hasMondayCardio = false;
let hasWednesdayStrength = false;
let hasFridayMobility = false;

items.forEach(function(it) {
  const wt = templates.find(function(t) { return t.id === it.workout_template_id; });
  if (!wt) return;
  const dur = wt.duration_minutes || 0;
  if (it.day_of_week === 'monday') {
    if (wt.workout_type === 'cardio' && dur < 30) {
      hasMondayCardio = true;
    }
  } else if (it.day_of_week === 'wednesday') {
    if (wt.workout_type === 'strength' && dur >= 30 && dur <= 45) {
      hasWednesdayStrength = true;
    }
  } else if (it.day_of_week === 'friday') {
    if ((wt.workout_type === 'mobility' || wt.workout_type === 'stretching') && dur >= 20) {
      hasFridayMobility = true;
    }
  }
});

// CP1 (0.34): Monday cardio workout under 30 minutes exists
checkpoints.push({ passed: hasMondayCardio, weight: 0.34 });

// CP2 (0.33): Wednesday strength workout 30–45 minutes exists
checkpoints.push({ passed: hasWednesdayStrength, weight: 0.33 });

// CP3 (0.33): Friday mobility/stretching workout ≥ 20 minutes exists
checkpoints.push({ passed: hasFridayMobility, weight: 0.33 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const bundles = JSON.parse(localStorage.getItem('nutrition_bundles') || '[]');

// All qualifying bundles per task criteria
const qualifyingBundles = bundles.filter(function(b) {
  if (!b || !b.is_active) return false;
  if (b.product_type !== 'bundle') return false;
  if (typeof b.price !== 'number' || b.price > 250) return false;
  return true;
});

if (qualifyingBundles.length < 2) {
  return 0;
}

const sorted = qualifyingBundles.slice().sort(function(a, b) {
  return (a.price || 0) - (b.price || 0);
});

const twoCheapest = sorted.slice(0, 2);
const maxMinutes = Math.max.apply(null, twoCheapest.map(function(b) { return b.total_minutes || 0; }));
const bestBundles = twoCheapest.filter(function(b) { return (b.total_minutes || 0) === maxMinutes; });

const nutritionCartItems = cartItems.filter(function(ci) {
  return ci && ci.item_type === 'nutrition_bundle' && !!ci.bundle_id;
});

// CP1 (0.4): At least one nutrition bundle item in cart is a qualifying bundle under $250
const anyQualifyingAdded = nutritionCartItems.some(function(ci) {
  return qualifyingBundles.some(function(b) { return b.id === ci.bundle_id; });
});
checkpoints.push({ passed: anyQualifyingAdded, weight: 0.4 });

// CP2 (0.6): At least one cart item is the better-value bundle among the two cheapest qualifying bundles
const bestBundleAdded = nutritionCartItems.some(function(ci) {
  return bestBundles.some(function(b) { return b.id === ci.bundle_id; });
});
checkpoints.push({ passed: bestBundleAdded, weight: 0.6 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

function getDateStr(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return null;
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

const challenges = JSON.parse(localStorage.getItem('challenges') || '[]');
const regs = JSON.parse(localStorage.getItem('challenge_registrations') || '[]');

// Qualifying challenge(s): free, 7 days, email delivery, wellbeing-focused
const targetChallenges = challenges.filter(function(c) {
  if (!c || !c.is_active) return false;
  if (c.price_type !== 'free') return false;
  if (c.duration_days !== 7) return false;
  if (c.delivery_channel !== 'email') return false;
  if (!c.focus) return false;
  return String(c.focus).toLowerCase().indexOf('wellbeing') !== -1;
});

if (!targetChallenges.length) {
  return 0;
}

const targetDate = '2026-03-09'; // next Monday relative to baseline 2026-03-03

const qualifyingRegs = regs.filter(function(r) {
  return r && targetChallenges.some(function(c) { return c.id === r.challenge_id; });
});

// CP1 (0.4): At least one registration exists for a qualifying 7-day free wellbeing email challenge
checkpoints.push({ passed: qualifyingRegs.length >= 1, weight: 0.4 });

// Registrations for that challenge with correct start date and email time
const correctTimeRegs = qualifyingRegs.filter(function(r) {
  return getDateStr(r.start_date) === targetDate && r.preferred_email_time === '08:00';
});

// CP2 (0.3): At least one such registration starts next Monday at 08:00
checkpoints.push({ passed: correctTimeRegs.length >= 1, weight: 0.3 });

// Of those, check themes include both sleep and mindfulness
const themeRegs = correctTimeRegs.filter(function(r) {
  const themes = Array.isArray(r.selected_themes) ? r.selected_themes : [];
  return themes.indexOf('sleep') !== -1 && themes.indexOf('mindfulness') !== -1;
});

// CP3 (0.3): At least one qualifying registration includes both required themes
checkpoints.push({ passed: themeRegs.length >= 1, weight: 0.3 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const lists = JSON.parse(localStorage.getItem('reading_list') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');

const list = lists[0];
if (!list || !Array.isArray(list.article_ids)) {
  return 0;
}

const savedArticles = list.article_ids
  .map(function(id) { return articles.find(function(a) { return a.id === id; }); })
  .filter(function(a) { return !!a; });

// Helper filters
const runningInjuryArticles = savedArticles.filter(function(a) {
  if (!a || !a.is_published) return false;
  if (a.category !== 'running') return false;
  if ((a.estimated_read_time_minutes || 0) >= 10) return false;
  const tags = Array.isArray(a.tags) ? a.tags : [];
  const hasInjury = tags.some(function(tag) { return String(tag).toLowerCase().indexOf('injury') !== -1; });
  return hasInjury;
});

const mentalResilienceArticles = savedArticles.filter(function(a) {
  if (!a || !a.is_published) return false;
  if (a.category !== 'mental_resilience') return false;
  if ((a.estimated_read_time_minutes || 0) >= 10) return false;
  return true;
});

const nutritionArticles = savedArticles.filter(function(a) {
  if (!a || !a.is_published) return false;
  if (a.category !== 'nutrition') return false;
  if ((a.estimated_read_time_minutes || 0) >= 10) return false;
  return true;
});

// CP1 (0.34): At least one saved short running article specifically about injury prevention
checkpoints.push({ passed: runningInjuryArticles.length >= 1, weight: 0.34 });

// CP2 (0.33): At least one saved short article about mental resilience
checkpoints.push({ passed: mentalResilienceArticles.length >= 1, weight: 0.33 });

// CP3 (0.33): At least one saved short article about nutrition
checkpoints.push({ passed: nutritionArticles.length >= 1, weight: 0.33 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const addOns = JSON.parse(localStorage.getItem('add_ons') || '[]');

// Membership items in cart that are monthly and include gym access
const membershipItems = cartItems.filter(function(ci) {
  if (!ci || ci.item_type !== 'membership' || !ci.membership_plan_id) return false;
  const plan = plans.find(function(m) { return m.id === ci.membership_plan_id; });
  if (!plan || !plan.is_active) return false;
  if (plan.billing_period !== 'monthly') return false;
  if (!plan.includes_gym_access) return false;
  return true;
}).map(function(ci) {
  const plan = plans.find(function(m) { return m.id === ci.membership_plan_id; });
  return { cartItem: ci, plan: plan };
});

// Yoga add-ons in cart that are monthly with at least one class per week
const yogaAddOnItems = cartItems.filter(function(ci) {
  if (!ci || ci.item_type !== 'add_on' || !ci.add_on_id) return false;
  const addOn = addOns.find(function(a) { return a.id === ci.add_on_id; });
  if (!addOn || !addOn.is_active) return false;
  if (addOn.category !== 'yoga') return false;
  if (addOn.billing_period !== 'monthly') return false;
  if ((addOn.classes_per_week || 0) < 1) return false;
  return true;
}).map(function(ci) {
  const addOn = addOns.find(function(a) { return a.id === ci.add_on_id; });
  return { cartItem: ci, addOn: addOn };
});

// CP1 (0.4): At least one qualifying monthly gym membership and one qualifying monthly yoga add-on are both in the cart
const hasBothTypes = membershipItems.length > 0 && yogaAddOnItems.length > 0;
checkpoints.push({ passed: hasBothTypes, weight: 0.4 });

// CP2 (0.6): There exists at least one membership + yoga add-on pair whose combined monthly price is ≤ $180
let hasAffordablePair = false;
if (hasBothTypes) {
  for (let i = 0; i < membershipItems.length && !hasAffordablePair; i++) {
    const mPrice = membershipItems[i].plan.price || 0;
    for (let j = 0; j < yogaAddOnItems.length; j++) {
      const aPrice = yogaAddOnItems[j].addOn.price || 0;
      if (mPrice + aPrice <= 180) {
        hasAffordablePair = true;
        break;
      }
    }
  }
}

checkpoints.push({ passed: hasAffordablePair, weight: 0.6 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);
